#include <iostream>

using namespace std;

int square(int n)
{
    int result = n * n; // lives in square's own stack frame
    return result;
}

int main()
{
    int x = 5; // lives in main's stack frame
    int y = square(x);

    cout << y << endl;

    return 0;
}

